var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CITIZEN_EXTRA_M_NULL","text":{"KOREA":"속이 메스꺼워…….","JPN":"吐き気がする……","ENG":"I don't feel too good...","TWN":"我……我好難受……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"CITIZEN_EXTRA_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CITIZEN_EXTRA_M_NULL","text":{"KOREA":"머리에서 목소리가 들려…… 하나가…… 돼야 해…….","JPN":"頭の中から声が聞こえる……一つに……なるんだ……","ENG":"I hear voices in my head... Must... become one...","TWN":"腦子裡有聲音……必須……合而為一……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"CITIZEN_EXTRA_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"지식<color=#ff3636>의 성찬</color>이 준비되었<color=#ff3636>다. 연회가</color> 시작<b>되</b>었다.","JPN":"知識<color=#ff3636>の聖餐</color>の準備が整っ<color=#ff3636>た。宴会が</color> 始ま<b>っ</b>た。","ENG":"The fe<color=#ff3636>ast of know</color>ledge has be<color=#ff3636>en prepared. The banquet</color> has st<b>arte</b>d.","TWN":"知識的<color=#ff3636>盛宴</color>準備好了。<color=#ff3636>宴會</color>開始<b>了</b>。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"<color=#ff3636>오랜</color> 갈구와 허기의 <color=#ff3636>끝</color>이 <color=#ff3636>마침</color>내 도래<b>했</b>다.","JPN":"<color=#ff3636>長い</color>渇きと飢えの<color=#ff3636>果て</color>が、<color=#ff3636>つい</color>に訪れ<b>た</b>のだ。","ENG":"The <color=#ff3636>long</color> thirst and hunger <b>are</b> <color=#ff3636>finally</color> coming to <color=#ff3636>an end</color>.","TWN":"<color=#ff3636>長久的</color>渴望與饑餓<color=#ff3636>終於</color>達<b>到</b>了盡<color=#ff3636>頭</color>。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"<color=#ff3636>성찬</color>의 주<color=#ffd34c>인</color>이 도착<b>했</b>다. 군<color=#ff3636>주</color>께서 도래<color=#ffd34c>하였</color>다.","JPN":"<color=#ff3636>聖餐</color>の<color=#ffd34c>主</color>が到着<b>し</b>た。君<color=#ff3636>主様</color>のお出<color=#ffd34c>まし</color>だ。","ENG":"The <color=#ff3636>host</color> <b>of</b> the f<color=#ffd34c>e</color>ast has arri<color=#ffd34c>ve</color>d. The <color=#ff3636>mon</color>arch has arrived.","TWN":"<color=#ff3636>盛宴</color>的主<color=#ffd34c>人</color><b>到</b>了。君<color=#ff3636>主</color>已<color=#ffd34c>降臨</color>。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"도망치던 사람들이 모두…… 변해버렸어요.","JPN":"逃げ惑っていた人たちが皆……変わり果ててしまった。","ENG":"Everyone who tried to run away... is distorted.","TWN":"逃跑的人全都……變異了。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"클리파 허수 에너지가 몸에 강제로 주입된 거예요.","JPN":"クリファ虚数エネルギーが体内に強制的に注入されたためです。","ENG":"They had Qlipha Imaginary Energy forcibly injected into their bodies.","TWN":"逆卡巴拉虛數能量被強行注入體內。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"적합자가 아닌 이들은 모두 몸이 무너져 내려 잔해가 되죠.","JPN":"身体が適応しなかった者は溶け落ち、残骸となってしまいます。","ENG":"Those who aren't suitable all turn into Remains.","TWN":"不合適的人都會崩潰變成殘骸。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"그리고 무너져 내린 사람들에겐 <color=#ffd34c>정보 오염</color>현상이 발생해요.","JPN":"そして、溶け落ちた者には、<color=#ffd34c>情報汚染</color>が発生します。","ENG":"And for those people, a phenomenon called <color=#ffd34c>data corruption</color> also occurs.","TWN":"並且那些人會發生<color=#ffd34c>資訊污染</color>的現象。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"어떤 대상에게 정보 오염이 발생하면 이 세계에 존재했던 대상에 대한 정보가 지워지고, 왜곡되죠.\xA0","JPN":"情報汚染が発生すると、現世に存在していた、その人物に関する情報は抹消され、捻じ曲げられるんです。\xA0","ENG":"When data corruption occurs on a target, all information that existed about the target is erased and distorted.\xA0","TWN":"當某個物件受到資訊污染時，所有關於這個個體的資訊就會被強行抹去或者扭曲掉。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"마치 그 사람이 세상에 존재하지 않았다는 것처럼.","JPN":"まるで、最初からこの世に存在していなかったかのように。","ENG":"As if that person had never existed in the first place.","TWN":"彷彿那個人從未存在於這個世界上一樣。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"정보 오염…… 그렇다면 내가 아버지를 기억하지 못하는 것도……?\xA0","JPN":"情報汚染……ということは、私がお父さんのことを覚えていないのも……？\xA0","ENG":"Data corruption... Maybe that's why I can't remember my father...?\xA0","TWN":"資訊污染……那麼我不記得爸爸的事也是……？"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_QM","text":{"KOREA":"이쪽이다! 잔해들이 이쪽으로 모이고 있어!","JPN":"こっちだ！　残骸がここに集まってきているぞ！","ENG":"This way! The Remains are gathering over here!","TWN":"在這邊！殘骸正在往這邊聚集！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"저 목소리는…….","JPN":"あの声は……","ENG":"That voice...","TWN":"那個聲音……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"분명 어디선가 들어본 것 같은 목소리예요.","JPN":"どこかで聞いたことがある。","ENG":"I think I've heard it somewhere before.","TWN":"那個聲音我肯定在哪聽過。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"확신할 수는 없지만…….","JPN":"確信は持てないけど……","ENG":"I can’t be certain, but...","TWN":"雖然無法肯定……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"머릿속 어둠이 시야를 가린다면…….","JPN":"頭の中の暗闇が視界を奪うのであれば……","ENG":"If the darkness in your mind blinds your vision...","TWN":"如果腦海中的黑暗遮蔽住視野……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"그걸 정화하는 게 우리들의 임무예요.","JPN":"それを浄化するのが私たちの使命です。","ENG":"It's our duty to purify it.","TWN":"淨化它是我們的職責。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"가시죠. 길을 뚫는 것은 제 전문이니까.","JPN":"行きましょう。道を確保するのは私の専門ですから。","ENG":"Let's go. I'm an expert when it comes to paving roads.","TWN":"走吧，開路可是我的專長呢。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"낯이 익은 목소리라면, 분명 당신과 관련이 있는 사람일 거예요.","JPN":"親しみのある声ということは、あなたと関わりがあった人物だと思います。","ENG":"If you recognize the voice, I'm sure that person has some correlation with you.","TWN":"如果是熟悉的聲音，肯定是和你有關的人。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"어쩌면 아버지일지도 모른다고 생각하고 계신 것 같은데, 그렇게 눈치 보지 않으셔도 돼요.","JPN":"お父さんかもしれないと思っているなら、正直にそう言ってください。","ENG":"I know you're thinking that he could be your father, so you don't have to be so careful around me.","TWN":"我知道你在想他可能是你的爸爸，在我面前不必那麼小心。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"맞아요. 아버지가 아닐까 생각하고는 있었죠.","JPN":"はい、お父さんなんじゃないかって思っています。","ENG":"You're right. I was thinking that he could be my father.","TWN":"沒錯，我確實是這麼想的。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}}]`);export{e as default};